/**
 * LendPaper Glossary Data
 * Comprehensive list of SMB funding and finance terms.
 */

const GLOSSARY = [
  { term: "\"A\" Paper", keywords: "prime super prime credit cash flow", def: "A borrower with very strong financials, prime or super-prime credit, and excellent cash flow. Often an ideal candidate for SBA loans or premium term products." },
  { term: "ABL (Asset-Backed Loan)", keywords: "asset based abl collateral", def: "A loan secured by a specific asset. If the loan is not repaid, the asset is taken by the lender." },
  { term: "Accounts Payable", keywords: "ap debt owed", def: "The total amount owed by a business to other businesses or vendors. A key current liability." },
  { term: "Accounts Receivables (AR)", keywords: "ar owed invoices", def: "Money owed to a business by its customers for goods or services sold on credit. Represents a short-term asset." },
  { term: "ACH", keywords: "automated clearing house electronic wire transfer", def: "Automated electronic transactions between banks. In alternative finance, often used interchangeably with MCA or RBF to describe daily/weekly automated micro-payments." },
  { term: "Alternative Lender", keywords: "non bank mca rbf uncollateralized", def: "Non-bank lenders providing products like MCAs, RBFs, or short-term installment loans. Usually uncollateralized with repayment terms under two years." },
  { term: "Amortization", keywords: "amortize fixed payments schedule", def: "Paying off debt over time with regular, scheduled installments that include both principal and interest. Term loans amortize; Lines of Credit generally do not." },
  { term: "Annual Interest Rate (AIR)", keywords: "air nominal rate simple interest", def: "The nominal yearly percentage charged on a funding product's principal balance, excluding origination fees, closing costs, or compounding effects. For example, a 10% AIR on a $100,000 commercial deal results in $10,000 of base interest per year, whereas the Annual Percentage Rate (APR) would be higher to reflect total borrowing fees.<br><br><strong>Relationship to Simple Interest:</strong> AIR is the annualized rate applied to a funding product, while simple interest is the calculation method that applies that rate strictly to the principal balance without charging interest on interest.<br><br><strong>Relationship to Factor Rate:</strong> AIR is a time-sensitive percentage where total costs decrease if paid off early, whereas a factor rate is a fixed decimal (e.g., 1.20) that locks in a flat fee upfront regardless of repayment speed." },
  { term: "APR (Annual Percentage Rate)", keywords: "apr interest cost", def: "The total annual cost of capital, including interest and fees, expressed as a percentage. Essential for comparing the true cost of funding products." },
  { term: "ATR (Amount, Term, Rate)", keywords: "atr variables", def: "The three primary variables of estimated terms: the dollar Amount, the Term length, and the Interest rate. These dictate the payment size." },
  { term: "Average Daily Deposits (ADD)", keywords: "add cash flow deposits", def: "The average amount of money a business deposits into its accounts on a daily basis. Used by underwriters to gauge cash flow volume." },
  { term: "Bank Verification (IBV/BV)", keywords: "ibv bv finicity plaid login", def: "A mechanism allowing lenders to securely connect to a business's bank account to view transaction history and verify income instantly, bypassing manual PDF uploads." },
  { term: "BLA (Business Loan Agreement)", keywords: "bla contract covenant legal", def: "A legally binding contract between a lender and a business borrower outlining loan terms, covenants, and collateral requirements." },
  { term: "BLOC (Business Line of Credit)", keywords: "bloc loc line of credit", def: "A flexible line of credit taken out specifically by a business to draw against for working capital as needed." },
  { term: "Bridge Loan", keywords: "bridge short term gap", def: "A short-term loan used to provide immediate cash flow until a company secures permanent financing or clears an existing obligation." },
  { term: "Buy Rate", keywords: "buy rate wholesale iso broker", def: "The base interest rate or cost of capital at which a lender will fund a deal to a broker/ISO, before any broker markup or commission is applied." },
  { term: "Cash Flow (CF)", keywords: "cf cash movement", def: "The net movement of money in and out of a business. A business can show a profit but have negative cash flow if expenses are due before invoices are paid." },
  { term: "Cash Flow Gap", keywords: "shortage timing", def: "A period when a business's outgoing cash obligations exceed its incoming cash, causing a temporary liquidity shortage." },
  { term: "CDL", keywords: "commercial drivers license trucking", def: "Commercial Driver's License. Required documentation for individuals operating commercial motor vehicles; critical for underwriting freight and trucking deals." },
  { term: "Clawback", keywords: "clawback recovery penalty", def: "The recovery of dispersed funds or commissions. Lenders can claw back funds from businesses in default, or claw back commissions from brokers if a deal is paid off too early." },
  { term: "COGS (Cost of Goods Sold)", keywords: "cogs direct costs", def: "The variable, direct costs of producing goods or services, typically including raw materials and direct labor." },
  { term: "COI (Certificate of Insurance)", keywords: "coi proof insurance", def: "A document proving that a business carries specific insurance coverage, often a required stipulation for funding." },
  { term: "COJ (Confession of Judgement)", keywords: "coj legal default guilty", def: "A legal agreement where a borrower admits fault for a debt before a dispute arises. Acts as an automatic guilty plea if the lender claims default. Highly restricted in certain states (e.g., NY, FL)." },
  { term: "Collateralized Loan", keywords: "secured asset backed", def: "A loan secured by specific assets that the lender can legally seize and liquidate if the borrower defaults." },
  { term: "Compounding Interest", keywords: "compound growth", def: "Interest calculated on the original principal amount AND on any accumulated past interest." },
  { term: "Concurrent Funding", keywords: "concurrent stack additional", def: "When a lender provides additional funding before a business has paid down enough of their current balance to be eligible for standard renewal." },
  { term: "Credit Memo", keywords: "credit memo narrative underwriting blast", def: "A comprehensive underwriting document that justifies proposed terms by analyzing cash flow, collateral, and risk. Tells the financial story of the borrower to the credit committee." },
  { term: "DataMerch", keywords: "datamerch risk flag reporting", def: "An alternative finance data warehouse that tracks borrower behavior, flagging defaults, slow payments, and suspicious activity for lenders." },
  { term: "DBA (Doing Business As)", keywords: "dba fictitious trade name", def: "When a company operates under a brand or trade name that is different from its legally registered corporate name." },
  { term: "Debt-to-Income (DTI)", keywords: "dti ratio leverage", def: "A ratio comparing total monthly debt payments to gross monthly income. A key metric used to assess over-leverage." },
  { term: "Default", keywords: "default failure break terms", def: "Failing to make timely payments and violating the core terms of a funding agreement. One step beyond mere delinquency." },
  { term: "Delayed Loan Agreement (DLA)", keywords: "dla staged draws construction", def: "A term loan where the total approved amount is disbursed in staged draws based on milestones (like construction phases) rather than a lump sum." },
  { term: "Delinquency", keywords: "late past due 30 60 90", def: "When a payment is past due but the account is not yet in full default. Usually tracked in 30, 60, and 90-day buckets, with increasing severity to credit profiles." },
  { term: "Depreciation", keywords: "depreciation 179 non cash", def: "A non-cash expense that reduces the taxable economic value of an asset over time. Often added back to net income during underwriting to determine true cash flow." },
  { term: "Derogatory Marks (DeRogs)", keywords: "derogs credit hit bankruptcy lien", def: "Severe negative items on a credit report, such as bankruptcies, collections, civil judgments, repossessions, liens, and foreclosures." },
  { term: "Double Taxation", keywords: "c corp tax liability", def: "A tax structure where a company pays income tax on its corporate profits, and then shareholders pay a second personal income tax on the dividends they receive (applies to C-Corps)." },
  { term: "Draw", keywords: "draw pull loc", def: "The action of pulling funds from an available Line of Credit into a business bank account, which initiates the debt balance and interest accrual." },
  { term: "Draw Fee", keywords: "draw fee loc charge", def: "A charge incurred every time a borrower pulls money out of their line of credit (e.g., 2% of the draw amount)." },
  { term: "DSCR (Debt Service Coverage Ratio)", keywords: "dscr coverage cash flow ebitda", def: "Measures a business's cash flow available to pay current debt obligations. Calculated as Net Operating Income divided by Total Debt Service. Lenders generally require 1.25 or higher.<br><br><strong>Calculation</strong>: If an investment property has a Net Operating Income (NOI) of $125,000 per year and the annual mortgage payments (debt service) are $100,000, the DSCR is 1.25 ($125,000 / $100,000). A DSCR of 1.25 means the property generates 25% more income than required to cover the debt." },
  { term: "EBITDA", keywords: "ebitda earnings profit", def: "Earnings Before Interest, Depreciation, Taxes, and Amortization. A standard measure of a company's operating performance and true profitability." },
  { term: "EIDL (Economic Injury Disaster Loan)", keywords: "eidl covid disaster", def: "A federal SBA loan program designed to provide working capital to businesses suffering substantial economic injury as a result of a declared disaster." },
  { term: "EIN (Employer Identification Number)", keywords: "ein tax id federal", def: "A unique nine-digit tax ID assigned to a business by the IRS, functioning like a Social Security Number for a corporate entity." },
  { term: "Equipment Financing", keywords: "eq hard asset collateral", def: "A funding product specifically used to purchase business equipment, where the equipment itself serves as the primary collateral for the debt." },
  { term: "Factor Rate (FR)", keywords: "factor rate fr multiplier", def: "A fixed decimal multiplier used to calculate total repayment on alternative financing (e.g., 1.25 on a $10k advance = $12.5k total payback). This is a fixed cost, not an annualized interest rate.<br><br><strong>Example</strong>: If a borrower takes a $10,000 cash advance at a 1.20 factor rate, the total payback amount is $12,000. Even if they pay it off in 2 months or 12 months, the total fee remains fixed at $2,000, unless the contract includes an early payoff discount." },
  { term: "FICO 8 / FICO 2", keywords: "fico credit score risk", def: "Standardized credit scoring models ranging from 300-850. FICO 8 is widely used for general creditworthiness; FICO 2 is often used by mortgage lenders." },
  { term: "Fixed Interest Rate", keywords: "fixed stable unchanged", def: "An interest rate that remains constant for the entire lifespan of the funding, resulting in predictable, unchanging monthly payments." },
  { term: "Flex Line of Credit (FLOC)", keywords: "floc app hybrid instant", def: "A modern, tech-driven hybrid of a LOC and installment loan. Allows instant, app-based draws, where each draw acts as a distinct mini-product with its own repayment term." },
  { term: "Float", keywords: "float reserves cushion", def: "The amount of cash reserves available in a business's operating accounts. Lenders prefer to see enough float to cover 3-6 months of operating expenses." },
  { term: "Forbearance", keywords: "forbearance pause hardship", def: "A temporary pause or reduction in payments granted by a lender during a period of financial hardship to prevent the borrower from defaulting." },
  { term: "Good Standing", keywords: "good standing sos active compliance", def: "A legal status indicating a company has met all statutory and administrative compliance requirements in its state of incorporation (e.g., filing reports, paying franchise taxes)." },
  { term: "Heter Iska / Murabaha", keywords: "heter iska shariah islamic jewish religious", def: "Legal frameworks in Jewish and Islamic commercial law used to structure financing as profit-sharing, asset purchases, or joint ventures to comply with religious prohibitions against charging interest." },
  { term: "Holdback", keywords: "holdback remit split rbf", def: "A fixed percentage of a business’s daily credit card sales or gross deposits that is automatically withheld by a processor to repay Revenue Based Financing." },
  { term: "Installment Loan", keywords: "fixed rate amortizing payments principal interest commercial installment", def: "A funding product where a business receives a lump sum upfront and repays it through a fixed schedule of regular, equal payments (daily, weekly, or monthly) over a set term. Each payment includes both principal and interest." },
  { term: "Installments", keywords: "installment payments scheduled regular repayment frequency daily weekly monthly", def: "The regular, scheduled periodic payments made to retire a debt or funding product. In alternative commercial finance, installments can be structured on a daily, weekly, or monthly frequency, with each payment typically auto-debited via ACH from the business's operating account." },
  { term: "Invoice Factoring", keywords: "factoring unpaid invoices ar", def: "Selling unpaid B2B invoices to a third party at a discount in exchange for immediate cash. The factoring company assumes the responsibility of collecting from the end customer." },
  { term: "Lien (Blanket / UCC-1)", keywords: "lien ucc claim collateral", def: "A legal claim on a property or asset securing a debt. A Blanket Lien (UCC-1) gives the lender a claim against all generic business assets (equipment, inventory, AR) if the borrower defaults." },
  { term: "Line of Credit (LOC)", keywords: "loc revolving pull bloc", def: "A flexible funding arrangement allowing a business to draw capital up to a preset limit. Interest only accrues on drawn amounts. Often revolving (replenishing as paid down)." },
  { term: "Liquidity", keywords: "liquidity cash conversion", def: "The ease and speed with which an asset can be converted into cash without affecting its market price." },
  { term: "Lockbox Account", keywords: "lockbox sweep payment control", def: "A payment model where B2B customers send payments to a lender-controlled bank account. The lender extracts their percentage and sweeps the remainder to the business’s operating account." },
  { term: "Net 30, 60, 90", keywords: "net terms invoice payment", def: "Standard commercial invoice payment terms indicating that full payment is expected within 30, 60, or 90 days from the invoice date." },
  { term: "Net Requirement", keywords: "net requirement 50 60 new money", def: "When using new funding to pay off existing debt, the required percentage of the new funding that must go directly to the borrower's working capital (e.g., a 'Net 50' on a $100k deal means the old debt cannot exceed $50k)." },
  { term: "Net Zero Consolidation", keywords: "net zero refinance consolidation restructure", def: "Replacing existing debt with new financial products specifically to optimize total interest or lower daily payments, without the requirement of netting additional working capital." },
  { term: "NRD (Non-Refundable Deposits)", keywords: "nrd deposit transfer personal", def: "Deposits moving into a business bank account that are not considered true sales revenue (e.g., owner capital injections, transfers from personal checking, or funding proceeds)." },
  { term: "NSF (Non-Sufficient Funds)", keywords: "nsf bounced overdraft", def: "When a bank account lacks the necessary balance to cover a transaction, resulting in a bounced payment and negative risk flags for underwriters." },
  { term: "Origination Fee", keywords: "origination points upfront cost", def: "An upfront fee charged by a lender for processing a new funding application, typically calculated as a percentage of the total funding amount." },
  { term: "Pass-Through Taxes", keywords: "pass through llc scorp k1", def: "A tax structure where the business entity does not pay federal income taxes. Instead, profits and losses flow directly to the owners' personal tax returns (applies to LLCs, S-Corps, Sole Props)." },
  { term: "Payables (Accounts Payable)", keywords: "payables ap vendors", def: "The total amount of money a business owes to its vendors or suppliers for goods and services purchased on credit." },
  { term: "Paydex (DUNS)", keywords: "paydex duns bradstreet credit", def: "A 1-100 business credit score from Dun & Bradstreet measuring payment performance. A score of 80+ indicates on-time payments to vendors." },
  { term: "Paynet Score", keywords: "paynet equifax risk", def: "A premier credit reporting metric from Equifax that assesses a business's payment history on funding products and leases to predict the probability of default." },
  { term: "Payoff Letter", keywords: "payoff letter demand statement", def: "A formal document issued by a lender detailing the exact amount required (including principal, interest, and fees) to fully settle a debt by a specific deadline." },
  { term: "Performance Guarantee", keywords: "performance guarantee revenue rbf", def: "An agreement utilized in RBFs where repayment is strictly tied to future revenue performance, rather than a fixed personal guarantee, protecting the owner if the business organically fails." },
  { term: "Personal Guarantee (PG)", keywords: "pg personal guarantee liability", def: "A legal promise by a business owner to be personally responsible for repaying a business debt if the corporate entity defaults." },
  { term: "Points", keywords: "points fee percentage", def: "A unit of measurement for funding fees, where one point equals exactly 1% of the total funding amount." },
  { term: "Position (Stacking)", keywords: "position stack 1st 2nd", def: "The hierarchy of active funding products. The first lender to fund is in 'first position' and gets paid back first in liquidation. Taking subsequent products creates 2nd, 3rd, or 4th positions." },
  { term: "Prime Rate", keywords: "prime rate wsj baseline", def: "The foundational interest rate set by the U.S. government/banks. Many commercial and SBA loans are priced as 'Prime + X%'." },
  { term: "Purchase Receivables", keywords: "purchase receivables rbf mca sale asset purchase usury future sales", def: "A commercial transaction where a funding provider buys a specific dollar amount of a business's future credit card sales or bank deposits at a discount. This is structured as an asset purchase, not a loan.<br><br><strong>Relationship to MCA & RBF</strong>: This is the core legal mechanism behind both Merchant Cash Advances (MCA) and Revenue-Based Financing (RBF). Because the funding provider is purchasing future assets rather than lending money, there is no fixed maturity date and no absolute covenant to repay. Therefore, traditional state usury laws (interest rate caps) do not apply, provided the contract is structured as a true sale with a reconciliation clause." },
  { term: "RBF (Revenue Based Financing)", keywords: "rbf mca merchant cash advance", def: "Capital provided in exchange for a percentage of future sales. Repaid dynamically via daily or weekly remits based on revenue volume. Not technically a loan." },
  { term: "Refinance", keywords: "refinance replace consolidation", def: "Replacing an existing debt obligation with a new one, generally to secure a lower interest rate, extend the term, or alter the payment structure." },
  { term: "Remit", keywords: "remit holdback percentage", def: "The specified percentage of daily revenue or deposits automatically withheld to retire a Revenue Based Financing advance." },
  { term: "Retention Pricing", keywords: "retention loyalty renew discount", def: "Loyalty benefits—such as waived remaining cost or discounted origination fees—offered to returning borrowers who renew their financing with the same lender." },
  { term: "Reverse Consolidation", keywords: "reverse consolidation daily weekly manage", def: "A specialized product where a new funder deposits money into a business account daily/weekly specifically to cover the payments of multiple existing short-term advances, easing immediate cash flow strain." },
  { term: "SBA 7(a) Loan", keywords: "sba 7a government guarantee", def: "The flagship loan program of the Small Business Administration, providing a government guarantee to banks to reduce risk when lending to small businesses for working capital or expansion." },
  { term: "Seasonality", keywords: "seasonality cycle revenue", def: "Predictable, cyclical fluctuations in a business's revenue based on the time of year (e.g., landscaping in summer, retail in Q4). Requires specialized underwriting." },
  { term: "Simple Interest", keywords: "simple interest principal", def: "Interest calculated exclusively on the original principal amount of the debt, without compounding." },
  { term: "Split Funding", keywords: "split funding passthrough stripe square", def: "An RBF repayment model where the credit card processor automatically intercepts the agreed-upon remit percentage before depositing the remaining batch into the merchant's bank account." },
  { term: "Stacking", keywords: "stacking position multiple loans risk", def: "The practice of a borrower taking out a new funding product or cash advance while a previous one is still active. Generally restricted as it drastically increases default risk." },
  { term: "Stipulation (Stip)", keywords: "stip requirement condition", def: "A specific condition or document (e.g., voided check, driver's license, updated P&L) required by an underwriter before a deal can be 'Clear to Close.'" },
  { term: "Subsequent Draw", keywords: "subsequent draw pull recurring", def: "Pulling additional capital against an open, established line of credit. Typically avoids full re-underwriting but usually incurs a standard draw fee." },
  { term: "Syndication", keywords: "syndication pool investors split", def: "A scenario where multiple investors or financial institutions pool their capital together to jointly fund a large or high-risk business, distributing the exposure." },
  { term: "Takedown Amount", keywords: "takedown draw portion", def: "The specific portion of an approved funding product or line of credit that a borrower actively chooses to draw or receive at a given time." },
  { term: "UCC (Uniform Commercial Code)", keywords: "ucc filing lien standard", def: "A standardized set of laws governing commercial transactions. A 'UCC filing' is the public notice a lender files to establish their legal lien on a borrower's assets." },
  { term: "Underwriting", keywords: "underwriting risk assessment decision", def: "The rigorous process wherein lenders evaluate a borrower's financial health, creditworthiness, and risk profile to determine funding eligibility and terms." },
  { term: "Usury", keywords: "usury illegal rate cap", def: "The illegal practice of lending money at unreasonably high, extortionate rates that exceed state-mandated interest rate caps. (Note: RBFs often avoid usury laws because they are asset purchases, not loans)." },
  { term: "Utilization", keywords: "utilization ratio credit limits", def: "The ratio of outstanding credit balances compared to total available credit limits. High utilization heavily damages credit scores, even with perfect payment history." },
  { term: "Variable Interest Rate", keywords: "variable floating prime", def: "An interest rate that fluctuates over the life of the funding, typically tied to an underlying index like the WSJ Prime Rate." },
  { term: "Working Capital", keywords: "working capital wc operational funds", def: "The capital available for a business's day-to-day operations (calculated as current assets minus current liabilities). Used for payroll, marketing, and rent—not real estate or heavy equipment." },
  { term: "Zeroing Out", keywords: "zeroing out balance risk depletion", def: "A major red flag where a business frequently depletes its bank account balance to zero by the end of the month, indicating tight margins and high default risk." },
  { term: "One-Pager (1-Page App)", keywords: "one pager app application submission broker", def: "A simplified, standard credit application used in commercial alternative finance to initiate underwriting, typically requiring basic business information and owner signatures." },
  { term: "Submission (Sub)", keywords: "sub submission bank statements app underwriting", def: "The initial package sent by a broker to a lender to request a credit decision, typically comprising a completed application and the 3–6 most recent months of business bank statements." },
  { term: "Sell Rate", keywords: "sell rate factor rate price borrower cost", def: "The final factor rate or interest rate presented to the merchant, which includes the broker's markup or commission added to the lender's buy rate." },
  { term: "Markup / Upsell", keywords: "markup upsell commission broker margin", def: "The pricing difference between a lender's wholesale buy rate and the sell rate presented to the borrower, representing the broker's margin or commission on the deal." },
  { term: "Restricted Industries", keywords: "restricted blacklisted sic naics high risk prohibited", def: "A list of high-risk business sectors (e.g., auto sales, legal services, adult entertainment) that specific commercial lenders choose not to fund due to high default or legal risks." },
  { term: "ISO (Independent Sales Organization)", keywords: "iso broker brokerage distributor agent sales", def: "An independent brokerage or agency that sources commercial leads, pre-qualifies small businesses, and submits funding files to alternative lenders." },
  { term: "Negative Days", keywords: "negative days overdraft balance dip risk red flag", def: "The number of calendar days in a month where a business bank account balance falls below zero. A critical risk metric where underwriters typically cap allowed negative days at 3 to 5 per month." },
  { term: "Daily Deposit Count", keywords: "daily deposit count deposit frequency cash flow", def: "The total number of separate revenue deposits into a business account per month. Underwriters look for high deposit frequency (e.g., at least 8 to 10 deposits) to ensure transaction diversity." },
  { term: "Concentration Risk", keywords: "concentration risk customer client revenue reliance", def: "The risk associated with a high percentage of a business's gross revenue (typically >30%) coming from a single customer or contract, leaving the cash flow highly vulnerable if that client delays payment." },
  { term: "Landlord Verification (LLV)", keywords: "llv landlord verification rent lease status", def: "A verification process performed by underwriters to confirm a merchant's lease status, monthly rent payments, and standing with their landlord to ensure eviction is not imminent." },
  { term: "Merchant Verification Call (MVC)", keywords: "mvc merchant call cov confirmation contract terms", def: "A final recorded confirmation call between the lender and the business owner right before funding to verify contract terms, bank details, and ensure no competitor stacking is occurring." },
  { term: "Tax Lien", keywords: "tax lien government irs back taxes public record", def: "A legal claim filed by federal or state tax authorities against a business's assets for unpaid taxes. Typically must be satisfied or placed on an active payment plan before funding." },
  { term: "Soft Pull vs. Hard Pull", keywords: "soft pull hard pull credit check fico inquiry", def: "A soft pull is a credit inquiry that does not affect the applicant's credit score (often used for initial screening). A hard pull is a formal credit check that can impact FICO scores, typically run right before contract execution." },
  { term: "Micro-Deposits", keywords: "micro deposits verification routing banking test ACH", def: "Small electronic test deposits (usually under $1.00) sent to a merchant's bank account to verify bank account ownership and active routing status before funding wire release." },
  { term: "Funding Call", keywords: "funding call wire release checklist final stips", def: "The final operational checklist stage where a lender confirms all underwriting stipulations have been satisfied and releases the ACH wire or wire transfer." },
  { term: "Inter-Company Transfers", keywords: "inter company transfers non revenue sister account transfers", def: "Non-revenue deposits moved between a merchant's sister corporations, shell entities, or personal checking accounts. Underwriters scrub these out of gross revenue calculations." },
  { term: "Average Ledger vs. Collected Balance", keywords: "ledger collected balance liquid cleared funds check float", def: "The ledger balance includes deposited checks that have not yet cleared. The collected balance represents the actual liquid, cleared funds available. Underwriters rely solely on collected balances for risk modeling." },
  { term: "Check Kiting", keywords: "check kiting fraud balance inflation deposits", def: "A fraudulent banking practice of writing checks between multiple accounts at different banks to artificially inflate ledger balances. Spotted by underwriters through matching deposit and withdrawal patterns." },
  { term: "K-1 Schedule", keywords: "k1 schedule tax partner llc ownership", def: "A federal tax document used to report a partner's share of income, losses, and deductions in partnership, S-Corp, or LLC entities." },
  { term: "UCC-3 Termination", keywords: "ucc3 termination release lien secretary of state", def: "A legal document filed with the Secretary of State to officially release and terminate a previous UCC-1 lien once a commercial debt has been paid in full." },
  { term: "UCC-3 Amendment (Subordination)", keywords: "ucc3 amendment subordination lien priority", def: "A legal filing that modifies an active UCC lien, often used to establish subordinate positioning or release specific collateral to a new lender." },
  { term: "Subordination Agreement", keywords: "subordination intercreditor senior junior lien priority", def: "A contract between two lenders establishing lien priority, where one lender agrees to stand in a junior position behind another's senior claim on business assets." },
  { term: "Active Corporate Status", keywords: "active corporate status good standing secretary of state", def: "A validation check of Secretary of State records confirming a business entity is legally active and has not been administrative dissolved, suspended, or forfeited." },
  { term: "Net Out (Net Payoff)", keywords: "net out net payoff refinancing consolidation", def: "The actual working capital a borrower receives from a new funding product after the remaining balances of existing debt have been paid off directly out of the gross proceeds.<br><br><strong>Example</strong>: A broker secures a new $150,000 cash advance for a business. However, the business still owes $50,000 on an active 2nd position advance. The new lender pays off the $50,000 directly, resulting in a Net Out of $100,000 wired to the merchant's bank account." },
  { term: "Early Payoff Discount (EPD)", keywords: "epd early payoff discount factor fee reduction", def: "A contractual discount that reduces the outstanding total payback amount of a factor-rate deal if the borrower pays off the balance significantly ahead of schedule." },
  { term: "Co-Brokering", keywords: "co brokering split commission broker partner", def: "A joint venture partnership where two independent brokers collaborate on a single deal and split the resulting markup or commission." },
  { term: "Advance Rate", keywords: "advance rate asset backed factoring inventory receivables percentage", def: "The maximum percentage of an asset's total appraised value (e.g., 80% of accounts receivable or 50% of inventory) that a lender is willing to advance as debt." },
  { term: "ACH Return Codes (R-Codes)", keywords: "ach return r codes nsf stop payment closed", def: "Standard banking codes indicating why an ACH sweep failed (e.g., R01 for NSF, R08 for Stop Payment, R10 for Customer Advises Not Authorized)." },
  { term: "Same-Day ACH", keywords: "same day ach express settlement wire speed", def: "An expedited ACH settlement network allowing electronic payment sweeps or payoffs to settle within the same business day rather than standard 1–2 day lag." },
  { term: "Re-Presentment", keywords: "re presentment ach sweep recovery NACHA retry", def: "The process of re-initiating a failed ACH draw after a return (such as an NSF). Governed strictly by NACHA frequency regulations." },
  { term: "LexisNexis InstantID", keywords: "lexisnexis instantid verification fraud background check", def: "A leading third-party database used by underwriters to verify commercial identities, cross-reference public records, and flag corporate fraud risks." },
  { term: "OFAC Search", keywords: "ofac search sanctions compliance federal terrorist check", def: "A mandatory federal database screen against the Office of Foreign Assets Control sanctions list to verify a borrower is not restricted from commercial commerce." },
  { term: "Factoring Rate", keywords: "factoring rate invoice discount fee B2B fee", def: "The percentage-based discount fee (commonly 1–3% per 30 days) charged by a factoring company to advance funds against outstanding invoices." },
  { term: "Purchase Order (PO) Financing", keywords: "purchase order po financing trade raw materials supplier", def: "Short-term funding advanced directly to a borrower's suppliers to cover production costs required to fulfill a verified customer purchase order." },
  { term: "$1 Buyout Lease", keywords: "one dollar buyout lease equipment ownership finance", def: "An equipment lease structure where the lessee assumes full ownership of the asset at the end of the term for a nominal $1.00 payment, behaving like an installment loan." },
  { term: "FMV (Fair Market Value) Lease", keywords: "fmv lease fair market value equipment balance sheet", def: "An equipment lease allowing the merchant to buy the equipment at term end for its fair market value, keeping the lease off the company balance sheet." },
  { term: "EFA (Equipment Finance Agreement)", keywords: "efa equipment finance agreement title lien collateral", def: "A commercial contract where the borrower owns the equipment from day one, while the lender holds a security lien on it until the contract is fully paid." },
  { term: "LTV (Loan-to-Value)", keywords: "ltv loan to value collateral real estate ratio", def: "The ratio of an active loan amount divided by the appraised value of the real estate serving as primary collateral.<br><br><strong>Calculation</strong>: If a business seeks a commercial mortgage of $700,000 to buy a warehouse appraised at $1,000,000, the LTV is 70% ($700,000 / $1,000,000). Lenders typically cap LTVs around 75% to 80% to maintain a protective equity cushion." },
  { term: "CLTV (Combined Loan-to-Value)", keywords: "cltv combined loan to value multi liens real estate", def: "The sum of all active loans and subordinate mortgages secured against a property divided by its total appraised value." },
  { term: "LTC (Loan-to-Cost)", keywords: "ltc loan to cost construction real estate", def: "The ratio of a commercial construction loan amount compared to the actual cost of building or renovating the project." },
  { term: "Debt Yield", keywords: "debt yield real estate cre underwriting noi return", def: "A real estate underwriting metric calculated as Net Operating Income divided by the Loan Amount, showing the lender's immediate return if they foreclosed." },
  { term: "Phase I ESA", keywords: "phase i esa environmental site assessment contamination survey", def: "A standard environmental survey of commercial property to verify the absence of historical soil or groundwater contamination before issuing a mortgage." },
  { term: "Owner-Occupied CRE", keywords: "owner occupied cre real estate sba 51 percent", def: "Commercial real estate where the borrowing business physically occupies at least 51% of the building's usable square footage, required for SBA mortgages." },
  { term: "SBSS Score (FICO)", keywords: "sbss score sba liquid credit bank models historical", def: "A credit scoring model ranging from 0 to 300 developed by FICO. Historically utilized by the SBA to pre-screen 7(a) applications, this strict score requirement has been retired in favor of banks' internal scoring models and underwriting guidelines." },
  { term: "Experian Intelliscore Plus", keywords: "experian intelliscore plus business credit rating score risk", def: "A leading commercial credit risk rating model ranging from 1 to 100 that predicts the likelihood of severe business payment delinquency." },
  { term: "Comparable Debt (Comp Debt)", keywords: "comparable debt comp debt credit history risk justification", def: "Previously held commercial credit accounts of a similar dollar size and term that the borrower successfully paid off, used by underwriters to justify larger credit lines." },
  { term: "Trade Line (Trade Reference)", keywords: "tradeline trade reference credit account history age", def: "An active or historical credit account listed on a consumer or commercial credit report (e.g., auto loan, business credit card, commercial lease)." },
  { term: "Credit Utilization Ratio", keywords: "utilization ratio credit balance limit revolving debt", def: "The percentage of available revolving credit a borrower is actively using, calculated as Current Balance divided by Total Credit Limit (typically kept under 30%)." },
  { term: "Charge-Off / Write-Off", keywords: "charge off write off bad debt loss creditor default", def: "A declaration by a creditor that an outstanding debt is unlikely to be collected and is written off as a bad-debt loss. A severe negative credit marker." },
  { term: "Adverse Action Notice", keywords: "adverse action notice ecoa disclosure decline letter credit report", def: "A legally mandated disclosure sent to an applicant explaining that credit was declined or approved on less favorable terms due to specific data found in their credit report." },
  { term: "Chapter 7 Bankruptcy", keywords: "chapter 7 bankruptcy liquidation court assets discharge", def: "A liquidation bankruptcy where a court-appointed trustee sells a debtor's non-exempt assets to pay off creditors, typically dissolving business operations." },
  { term: "Chapter 11 Bankruptcy", keywords: "chapter 11 bankruptcy restructuring business reorganization dip", def: "A corporate reorganization bankruptcy allowing a business to remain active and operational while restructuring its debts under court oversight." },
  { term: "Chapter 13 Bankruptcy", keywords: "chapter 13 bankruptcy wage earner personal reorganization sole prop", def: "A court-approved debt reorganization and repayment plan for individuals and sole proprietors spanning 3 to 5 years." },
  { term: "Discharged vs. Dismissed Bankruptcy", keywords: "discharged dismissed bankruptcy case status resolution", def: "Discharged indicates the court legally wiped away liability for eligible debts. Dismissed means the court threw out the case without erasing debts, letting creditors resume collections." },
  { term: "Cross-Corporate Guarantee", keywords: "cross corporate guarantee joint liability sister entities multi business", def: "A legal agreement where multiple distinct business entities owned by the same principal guarantee a credit product, making all entities jointly and severally liable." },
  { term: "Authorized Signatory", keywords: "authorized signatory corporate officer bind signature contract", def: "The individual legally authorized to sign contracts and bind a corporation or LLC to credit agreements (e.g., President, Managing Member)." },
  { term: "ECOA Account Ownership Codes", keywords: "ecoa codes ownership status individual joint authorized user", def: "Standardized codes on credit reports indicating account responsibility, such as J for Joint, I for Individual, or A for Authorized User." },
  { term: "MOP Codes (Method of Payment)", keywords: "mop codes payment history rating revolving installment default", def: "Standardized credit report grid codes (e.g., R1/I1 for on-time, R5 for 120+ days late, R9 for severe default or charge-off) tracking payment health." },
  { term: "High Credit", keywords: "high credit max balance historical credit report", def: "The highest balance a borrower has ever carried on an active or closed revolving credit account, reported directly on credit files." },
  { term: "DLA (Date of Last Activity)", keywords: "dla date last activity credit update statute limitations", def: "The exact date a credit account was last updated, paid, or drawn against. Vital for tracking aging collections and statutes of limitations." },
  { term: "Trade Status", keywords: "trade status credit health current past due collection chargeoff", def: "The current standing of a credit account reported on a bureau file (e.g., 'Current', 'Past Due', 'Collection', 'Charge-Off')." },
  { term: "DBT (Days Beyond Terms)", keywords: "dbt days beyond terms supplier vendor payment speed", def: "The average number of days past the invoice due date that a business takes to pay its commercial suppliers or vendors.<br><br><strong>Example</strong>: A business buys raw inventory from a supplier with payment terms of Net 30. If the business pays the invoice on day 45, it is 15 days past the due date, resulting in a DBT of 15." },
  { term: "D&B Rating", keywords: "dnb rating dun bradstreet financial strength creditworthiness", def: "Dun & Bradstreet's composite financial rating (e.g., 5A4) indicating a business's net worth and overall creditworthiness bracket." },
  { term: "DUNS Number", keywords: "duns number registration identifier dun bradstreet corporate", def: "A unique, nine-digit registration number issued by Dun & Bradstreet to identify distinct commercial businesses globally." },
  { term: "PayNet Delinquency Index (PDI)", keywords: "paynet delinquency index pdi sector defaults commercial", def: "A leading index measuring the percentage of commercial loans and leases that are 30, 60, or 90 days past due within specific industries." },
  { term: "PayNet MasterScore", keywords: "paynet masterscore default probability credit scoring commercial", def: "A proprietary commercial credit risk score built by PayNet predicting the likelihood of business default or severe delinquency." },
  { term: "FCRA (Fair Credit Reporting Act)", keywords: "fcra fair credit reporting act federal law privacy accuracy", def: "The federal law regulating the collection, dissemination, and accuracy of consumer credit information reported by credit bureaus." },
  { term: "Statute of Limitations (Debt)", keywords: "statute limitations debt collection lawsuit timeframe expiration", def: "The state-mandated legal timeframe during which a creditor can sue a debtor to legally collect an unpaid debt balance." },
  { term: "FDCPA (Fair Debt Collection Practices Act)", keywords: "fdcpa fair debt collection practices act regulations harassment", def: "Federal regulations protecting consumers by restricting how third-party debt collectors can communicate and collect outstanding debts." },
  { term: "Super-Prime Credit", keywords: "super prime credit score tier prime best rates pristine FICO", def: "The highest credit tier (typically FICO 780 to 850) representing borrowers with pristine financial history, who qualify for the lowest commercial rates and premium bank/SBA products." },
  { term: "Prime Credit", keywords: "prime credit score tier strong standard rate bank terms FICO", def: "A highly creditworthy tier (typically FICO 660 to 779) representing borrowers with strong financial profiles who qualify for standard commercial bank terms and prime-rate products." },
  { term: "Near-Prime Credit (Alt-A)", keywords: "near prime alt a credit score tier alternative FICO", def: "A credit tier falling just below prime standards (typically FICO 620 to 659) due to minor blemishes or shorter business history, often served by alternative commercial term lenders." },
  { term: "Subprime Credit", keywords: "subprime credit score tier high risk factor rate mca FICO", def: "A higher-risk credit tier (typically FICO 580 to 619) with noticeable credit blemishes, collections, or past delinquencies, usually qualifying for factor-rate alternative products." },
  { term: "Deep Subprime Credit", keywords: "deep subprime credit score tier severe risk mca collateral FICO", def: "The highest-risk credit tier (typically FICO below 580) characterized by severe credit blemishes (such as active defaults or tax liens). They are generally restricted to daily merchant cash advances or asset-backed funding." },
  { term: "TILA (Truth in Lending Act)", keywords: "tila truth lending act federal disclosure apr consumer", def: "A federal consumer protection law requiring lenders to provide clear, standardized disclosures of credit costs, interest rates, and annual percentage rates (APR) before contract signing." },
  { term: "Commercial Disclosure Laws (State-Level)", keywords: "commercial disclosure laws state level ca sb1235 ny sb5470 apr cost capital", def: "State-level regulations (such as California's SB 1235 and New York's SB 5470) requiring commercial lenders and alternative finance providers to provide TILA-like standardized disclosures of APR, finance charges, and terms to small business owners.<br><br><strong>APR Mandate</strong>: Under these laws, alternative finance providers (including MCA and RBF funders) must calculate and declare an estimated Annual Percentage Rate (APR) alongside factor rates or total finance charges, allowing small businesses to easily compare commercial products to traditional term loans." },
  { term: "KYC (Know Your Customer)", keywords: "kyc know your customer compliance identity verification fraud prevention", def: "A mandatory commercial compliance process designed to verify the true identity of a business owner and the legitimacy of the entity, preventing identity theft, fraud, and money laundering." },
  { term: "BSA / AML (Bank Secrecy Act / Anti-Money Laundering)", keywords: "bsa aml bank secrecy anti money laundering compliance federal", def: "A suite of federal regulations requiring financial institutions and lenders to implement internal controls, monitor transactions, and report suspicious activities to prevent money laundering and terrorist financing." },
  { term: "CIP (Customer Identification Program)", keywords: "cip customer identification program patriot act compliance verify", def: "A formal internal compliance procedure mandated by the USA PATRIOT Act requiring commercial lenders to verify the identity of any individual seeking to open a business funding account." },
  { term: "UDAAP (Unfair, Deceptive, or Ab abusive Acts or Practices)", keywords: "udaap unfair deceptive abusive compliance cfpb advertising consumer", def: "Federal regulatory standards enforced by the CFPB prohibiting financial product providers from engaging in misleading, deceptive, or abusive practices in credit marketing, terms, or collections." },
  { term: "GLBA (Gramm-Leach-Bliley Act)", keywords: "glba gramm leach bliley compliance data privacy npi security", def: "A federal privacy law requiring financial institutions and commercial lenders to safeguard borrowers' non-public personal information (NPI) and provide clear disclosures regarding data sharing." },
  { term: "SAR (Suspicious Activity Report)", keywords: "sar suspicious activity report bsa aml fincen transaction alert", def: "A confidential compliance document filed by financial institutions with FinCEN to report transaction patterns that suggest money laundering, tax evasion, fraud, or other illegal activities." },
  { term: "TCPA / DNC (Do Not Call)", keywords: "tcpa dnc do not call telephone protection compliance cold calling broker solicitation", def: "The Telephone Consumer Protection Act (TCPA) and the National Do Not Call (DNC) Registry are federal regulations restricting unsolicited commercial cold-calling, automated dialing systems, and pre-recorded voice messages.<br><br><strong>Sales Compliance</strong>: Absolute must-know for BDRs and ISO cold-callers. Failing to cross-reference leads against the DNC registry or violating TCPA regulations regarding auto-dialers can expose brokerages and lenders to severe statutory fines (up to $1,500 per individual call violation)." },
  { term: "TIB (Time in Business)", keywords: "tib time in business age operating history underwriting criteria metrics", def: "The total duration a business has been actively operating and registered. A key metric in alternative commercial finance underwriting; most standard MCA/RBF funders require at least 3 to 6 months TIB, whereas bank and SBA products often require 2+ years." },
  { term: "NAICS Code", keywords: "naics code north american industry classification census classification restricted compliance SBA", def: "North American Industry Classification System. A standardized six-digit code used by federal agencies and commercial lenders to classify business establishments by industry sector. Essential for identifying restricted/prohibited industries and evaluating SBA eligibility." },
  { term: "SIC Code", keywords: "sic code standard industrial classification industry classification restricted compliance", def: "Standard Industrial Classification. A four-digit system used to classify business establishments by their primary economic activity, often utilized in tandem with NAICS by commercial underwriters to cross-reference credit risk and industry restrictions." },
  { term: "Solve-for-X", keywords: "solve for x calculator solver algebraic variables factor rate payment term pricing model", def: "An algebraic pricing solver used in commercial underwriting to calculate a single missing variable—such as the factor rate, monthly payment, term length, or gross funding amount—when the other variables are already known." },
  { term: "SOS (Secretary of State)", keywords: "sos secretary of state filing good standing corporation registration entity validation", def: "The state-level government office responsible for corporate registrations, entity formation, and maintaining public records. Commercial funders verify SOS records to ensure a business has active legal status and that their UCC liens are filed correctly." },
  { term: "Home-Based Business (Residential Risk)", keywords: "home based business residential address address validation places risk audit underwriting", def: "A commercial entity operating directly out of a residential property. While many MCA and RBF funders approve home-based businesses, traditional equipment leasing, bank, and SBA products enforce strict property-use limits, often requiring a physical commercial storefront or warehouse." },
  { term: "Objection Handling", keywords: "objection handling talk tracks consultative pitch close panic bar sales strategy", def: "A structured sales methodology used by commercial brokers to address and resolve merchant hesitations—such as high factor rates, short terms, or daily payment stress—by framing funding as an investment with clear ROI rather than a traditional debt burden." },
  { term: "Cost of Capital", keywords: "cost of capital interest borrowing cost fees yield pricing model", def: "The total cumulative expense a business incurs to secure funding, encompassing factor fees, simple interest, origination points, and closing costs. Represented in calculators as the total payback amount minus the net funded amount." },
  { term: "Alternative Funder", keywords: "alternative funder non bank capital provider mca rbf direct funder", def: "A non-bank direct capital provider that deploys uncollateralized commercial products like Merchant Cash Advances (MCAs) or Revenue-Based Financing (RBF). They typically emphasize speed and cash flow volume over pristine personal credit." },
  { term: "Reconciliation Clause", keywords: "reconciliation clause mca rbf true sale usury protection cash flow bank deposits", def: "A mandatory contractual clause in Merchant Cash Advances and Revenue-Based Financing. It permits the merchant to request adjustments to their daily or weekly payment sweep based on actual revenue fluctuations, confirming the transaction is structured as a true asset purchase rather than a usurious loan." }
];

// Exporting for use in other files
if (typeof module !== 'undefined' && module.exports) {
  module.exports = GLOSSARY;
}
